// Node: Code - Calculate Event DateTime
const eventDate = $('Google Sheets: Append Registrant').first().json.event_date;   // "2025-02-15"
const eventTime = $('Google Sheets: Append Registrant').first().json.event_time;   // "14:00"
const timezone  = $('Google Sheets: Append Registrant').first().json.timezone;     // "America/New_York"

// Build ISO string
const eventISO = `${eventDate}T${eventTime}:00`;
const eventMs  = new Date(eventISO).getTime();
const nowMs    = Date.now();

// 24h before = eventMs - 86400000
// 1h before  = eventMs - 3600000
const wait24hMs = Math.max(0, (eventMs - 86400000) - nowMs);
const wait1hMs  = Math.max(0, (eventMs - 3600000)  - nowMs);

return items.map(item => ({
  json: {
    ...item.json,
    event_iso:     eventISO,
    event_ms:      eventMs,
    wait_24h_ms:   wait24hMs,
    wait_1h_ms:    wait1hMs,
    reminder_24h_at: new Date(eventMs - 86400000).toISOString(),
    reminder_1h_at:  new Date(eventMs - 3600000).toISOString()
  }
}));

const input = items[0].json.body;
const eventDuration = input.event_duration_minutes || 60;

return input.attendees.map(attendee => ({
  json: {
    email: (attendee.email || "").toLowerCase().trim(),
    attendance_status: attendee.status,
    join_time: attendee.join_time || null,
    leave_time: attendee.leave_time || null,
    duration_minutes: attendee.duration_minutes || 0,
    questions_asked: attendee.questions_asked || 0,
    poll_responses: attendee.poll_responses || 0,
    chat_messages: attendee.chat_messages || 0,

    event_name: input.event_name,
    event_date: input.event_date,
    event_duration_minutes: eventDuration,

    watch_percentage: Math.round(
      ((attendee.duration_minutes || 0) / eventDuration) * 100
    ),

    engagement_score:
      ((attendee.questions_asked || 0) * 10) +
      ((attendee.poll_responses || 0) * 5) +
      ((attendee.chat_messages || 0) * 2) +
      Math.round(((attendee.duration_minutes || 0) / eventDuration) * 100)
  }
}));

