=Analyze this webinar attendee and return a JSON object.

Attendee data:
- Email: {{ $json.email }}
- Name: {{ $json.name }}
- Company: {{ $json.company }}
- Attendance status: {{ $json.attendance_status }}
- Watch percentage: {{ $json.watch_percentage }}%
- Duration watched: {{ $json.duration_minutes }} minutes out of {{ $json.event_duration_minutes }}
- Questions asked: {{ $json.questions_asked }}
- Poll responses: {{ $json.poll_responses }}
- Chat messages: {{ $json.chat_messages }}
- Engagement score: {{ $json.engagement_score }}
- Lead source: {{ $json.source }}
Segmentation rules:
- HOT: attended AND (watch_percentage >= 80 OR engagement_score >= 90)
- WARM: attended AND (watch_percentage between 30 and 79) OR attended with low engagement
- COLD: no-show OR watch_percentage < 30

Return ONLY this JSON:
{
  "segment": "HOT|WARM|COLD",
  "reason": "one sentence explanation referencing specific data points",
  "confidence": 0.0 to 1.0,
  "email_tone": "urgent|nurture|re-engage",
  "key_signal": "the single most important data point that drove this classification",
  "email_body": "write a 3-sentence personalized follow-up email body for this specific
                 person. Reference their company and specific engagement signals.
                 Sign off as 'The AI Automation Team'."
}

parameters.jsCode:
return items.map(item => {
  let aiResult = {};

  try {
    const content = item.json.output;

    // Clean markdown fences if present
    const cleaned = content
      .replace(/```json\n?/gi, '')
      .replace(/```\n?/gi, '')
      .trim();

    aiResult = JSON.parse(cleaned);

  } catch (e) {
    // Fallback if parsing fails
    aiResult = {
      segment: 'WARM',
      reason: 'AI parse error – defaulting to WARM for manual review',
      confidence: 0.0,
      email_tone: 'nurture',
      key_signal: 'parse_error',
      email_body: 'Thank you for attending our webinar. We hope you found it valuable and will follow up soon.'
    };
  }

  return {
    json: {
      ...item.json,

      segment: aiResult.segment || 'WARM',
      segment_reason: aiResult.reason || '',
      confidence: aiResult.confidence ?? 0,
      email_tone: aiResult.email_tone || 'nurture',
      key_signal: aiResult.key_signal || '',
      ai_email_body: aiResult.email_body || ''
    }
  };
});

