return items.map(item => {
  let summary = {};
  try {
    const content = item.json.choices[0].message.content;
    const cleaned = content
      .replace(/```json\n?/gi, '')
      .replace(/```\n?/gi, '')
      .trim();
    summary = JSON.parse(cleaned);
  } catch(e) {
    summary = {
      email_subject:       'Watch the replay: ' + (item.json.event_name || 'Our Webinar'),
      preview_text:        'The full recording is now available for you.',
      headline:            'The Replay Is Ready',
      summary_paragraph:   'Thank you for your interest in our webinar. The recording covers everything discussed during the live session.',
      top_3_takeaways:     ['Key automation strategies', 'Free tool stack revealed', 'Step-by-step implementation'],
      cta_text:            'Watch Now',
      ps_line:             'P.S. This replay expires in 7 days – watch it while it\'s fresh.'
    };
  }
  return {
    json: {
      ...item.json,
      summary_email_subject:   summary.email_subject,
      summary_preview:         summary.preview_text,
      summary_headline:        summary.headline,
      summary_paragraph:       summary.summary_paragraph,
      summary_takeaways:       (summary.top_3_takeaways || []).join('|||'),
      summary_cta:             summary.cta_text,
      summary_ps:              summary.ps_line
    }
  };
});

